import React, { useState, useEffect } from 'react';
import axios from 'axios';
import {
  getUnits,
  getTopics,
  getSubtopics,
  DEFAULT_UNIT_ID,
  DEFAULT_TOPIC_ID,
  DEFAULT_SUBTOPIC_ID
} from '../curriculumConfig';

function AddQuestion() {
  const units = getUnits();
  const [unitId, setUnitId] = useState(DEFAULT_UNIT_ID);
  const [topicId, setTopicId] = useState(DEFAULT_TOPIC_ID);
  const [subtopicId, setSubtopicId] = useState(DEFAULT_SUBTOPIC_ID);

  const [type, setType] = useState('Theory-based MCQ');
  const [question, setQuestion] = useState('');
  const [questionImage, setQuestionImage] = useState(null);
  const [options, setOptions] = useState({ a: '', b: '', c: '', d: '' });
  const [optionImages, setOptionImages] = useState({ a: null, b: null, c: null, d: null });
  const [correctAnswer, setCorrectAnswer] = useState(0);
  const [explanation, setExplanation] = useState('');
  const [explanationImage, setExplanationImage] = useState(null);
  const [isPublished, setIsPublished] = useState(false);
  const [loading, setLoading] = useState(false);
  const [message, setMessage] = useState('');

  // Get topics for selected unit
  const topics = unit ? Object.keys(CURRICULUM[unit]) : [];
  // Get subtopics for selected topic
  const subtopics = unit && topic ? CURRICULUM[unit][topic] : [];

  useEffect(() => {
    if (unit && CURRICULUM[unit]) {
      const newTopics = Object.keys(CURRICULUM[unit]);
      setTopic(newTopics[0]);
      setSubtopic(CURRICULUM[unit][newTopics[0]][0]);
    }
  }, [unit]);

  useEffect(() => {
    if (unit && topic && CURRICULUM[unit][topic]) {
      setSubtopic(CURRICULUM[unit][topic][0]);
    }
  }, [topic]);

  const handleOptionChange = (key, value) => {
    setOptions(prev => ({ ...prev, [key]: value }));
  };

  const handleImageUpload = async (e, type) => {
    const file = e.target.files[0];
    if (!file) return;

    const formData = new FormData();
    formData.append('image', file);

    try {
      const response = await axios.post('/api/questions/upload', formData, {
        headers: { 'Content-Type': 'multipart/form-data' }
      });
      const imageUrl = response.data.imageUrl;

      if (type === 'question') {
        setQuestionImage(imageUrl);
      } else if (type === 'explanation') {
        setExplanationImage(imageUrl);
      } else if (['a', 'b', 'c', 'd'].includes(type)) {
        setOptionImages(prev => ({ ...prev, [type]: imageUrl }));
      }
    } catch (error) {
      alert('Image upload failed: ' + error.message);
    }
  };

  const removeImage = (type) => {
    if (type === 'question') {
      setQuestionImage(null);
    } else if (type === 'explanation') {
      setExplanationImage(null);
    } else if (['a', 'b', 'c', 'd'].includes(type)) {
      setOptionImages(prev => ({ ...prev, [type]: null }));
    }
  };

  const handleSubmit = async (e) => {
    e.preventDefault();
    setLoading(true);
    setMessage('');

    try {
      const answerMap = { 0: 'a', 1: 'b', 2: 'c', 3: 'd' };

      await axios.post('/api/questions', {
        unit,
        topic,
        subtopic,
        type,
        question,
        questionImage,
        options,
        optionImages,
        correctAnswer,
        explanation,
        explanationImage,
        is_published: isPublished,
        status: 'pending'
      });

      setMessage('Question saved successfully!');
      // Reset form
      setQuestion('');
      setQuestionImage(null);
      setOptions({ a: '', b: '', c: '', d: '' });
      setOptionImages({ a: null, b: null, c: null, d: null });
      setCorrectAnswer(0);
      setExplanation('');
      setExplanationImage(null);
    } catch (error) {
      setMessage('Error saving question: ' + error.message);
    } finally {
      setLoading(false);
    }
  };

  const getImagePreview = (imageUrl) => {
    if (!imageUrl) return null;
    return imageUrl.startsWith('http') ? imageUrl : `http://localhost:5000${imageUrl}`;
  };

  return (
    <div className="tab-content">
      <h2>Add Question</h2>

      {message && (
        <div className={message.includes('Error') ? 'error-message' : 'success-message'}>
          {message}
        </div>
      )}

      <form onSubmit={handleSubmit}>
        {/* Hierarchy Selection */}
        <div className="hierarchy-section">
          <h3>Category Hierarchy</h3>
          <div className="form-row three-col">
            <div className="form-group">
              <label>Unit</label>
              <select value={unit} onChange={(e) => setUnit(e.target.value)}>
                {units.map(u => <option key={u} value={u}>{u}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Topic</label>
              <select value={topic} onChange={(e) => setTopic(e.target.value)}>
                {topics.map(t => <option key={t} value={t}>{t}</option>)}
              </select>
            </div>
            <div className="form-group">
              <label>Subtopic</label>
              <select value={subtopic} onChange={(e) => setSubtopic(e.target.value)}>
                {subtopics.map(st => <option key={st} value={st}>{st}</option>)}
              </select>
            </div>
          </div>
        </div>

        <div className="form-group">
          <label>Question Type</label>
          <select value={type} onChange={(e) => setType(e.target.value)}>
            <option>Theory-based MCQ</option>
            <option>Numerical/Problem-based</option>
            <option>Assertion-Reason</option>
            <option>Match the Following</option>
            <option>Statement type (True/False)</option>
            <option>Diagram-based</option>
          </select>
        </div>

        {/* Question Section */}
        <div className="section">
          <h3>Question</h3>
          <div className="form-group">
            <label>Question Text</label>
            <textarea
              value={question}
              onChange={(e) => setQuestion(e.target.value)}
              rows={4}
              required
              placeholder="Enter the question text here..."
            />
          </div>

          <div className="form-group">
            <label>Question Image (Optional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => handleImageUpload(e, 'question')}
            />
            {questionImage && (
              <div className="image-preview-container">
                <img
                  src={getImagePreview(questionImage)}
                  alt="Question"
                  className="image-preview"
                />
                <button type="button" className="btn-remove-image" onClick={() => removeImage('question')}>
                  Remove
                </button>
              </div>
            )}
          </div>
        </div>

        {/* Options Section */}
        <div className="section">
          <h3>Options</h3>
          {['a', 'b', 'c', 'd'].map((opt, idx) => (
            <div key={opt} className="option-row">
              <div className="option-input-group">
                <div className="form-group option-text">
                  <label>Option {opt.toUpperCase()}</label>
                  <input
                    value={options[opt]}
                    onChange={(e) => handleOptionChange(opt, e.target.value)}
                    required
                    placeholder={`Enter option ${opt.toUpperCase()}`}
                  />
                </div>
                <div className="form-group option-image">
                  <label>Image</label>
                  <input
                    type="file"
                    accept="image/*"
                    onChange={(e) => handleImageUpload(e, opt)}
                  />
                  {optionImages[opt] && (
                    <div className="image-preview-small">
                      <img
                        src={getImagePreview(optionImages[opt])}
                        alt={`Option ${opt.toUpperCase()}`}
                      />
                      <button type="button" className="btn-remove-small" onClick={() => removeImage(opt)}>
                        x
                      </button>
                    </div>
                  )}
                </div>
                <div className="correct-answer-radio">
                  <input
                    type="radio"
                    name="correctAnswer"
                    id={`correct-${opt}`}
                    checked={correctAnswer === idx}
                    onChange={() => setCorrectAnswer(idx)}
                  />
                  <label htmlFor={`correct-${opt}`}>Correct</label>
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Explanation Section */}
        <div className="section">
          <h3>Explanation</h3>
          <div className="form-group">
            <label>Explanation Text</label>
            <textarea
              value={explanation}
              onChange={(e) => setExplanation(e.target.value)}
              rows={4}
              placeholder="Enter the detailed explanation here..."
            />
          </div>

          <div className="form-group">
            <label>Explanation Image (Optional)</label>
            <input
              type="file"
              accept="image/*"
              onChange={(e) => handleImageUpload(e, 'explanation')}
            />
            {explanationImage && (
              <div className="image-preview-container">
                <img
                  src={getImagePreview(explanationImage)}
                  alt="Explanation"
                  className="image-preview"
                />
                <button type="button" className="btn-remove-image" onClick={() => removeImage('explanation')}>
                  Remove
                </button>
              </div>
            )}
          </div>
        </div>

        <div className="form-group">
          <label className="checkbox-label">
            <input
              type="checkbox"
              checked={isPublished}
              onChange={(e) => setIsPublished(e.target.checked)}
            />
            Publish to Student Portal
          </label>
        </div>

        <button type="submit" className="btn-primary" disabled={loading}>
          {loading ? 'Saving...' : 'Save Question'}
        </button>
      </form>
    </div>
  );
}

export default AddQuestion;
